SELECT p.*, c.category_name FROM product p LEFT JOIN category c ON p.category_id = c.category_id
AND (p.product_name LIKE CONCAT('%', #{keyword}, '%') OR p.barcode LIKE CONCAT('%', #{keyword}, '%'))
AND p.category_id = #{categoryId}
ORDER BY p.product_id DESC LIMIT #{offset}, #{limit}

